// import logo from "./logo.svg";
import "./App.css";
import CounterPages from "./components/counterPages";
import { BrowserRouter, Routes, Route, Link } from "react-router-dom";
import React, { Component } from "react";

class App extends Component {
  state = {
    pages: [
      { id: 1, name: "page #1", route: "/page1" },
      { id: 2, name: "page #2", route: "/page2" },
    ],
    index: 1,
  };

  //adds a page of counters
  handleAddPage = () => {};

  //deletes selected page of counters
  handleDeletePage = () => {};

  //cycles forward a page to the next counter
  handleNextPage = () => {};

  //cycles back a page to the previous counter
  handleBackPage = () => {};

  render() {
    return (
      <div>
        <BrowserRouter>
          <div>
            <Routes>
              <Route exact path="/" element={<Home />}></Route>
              <Route exact path="/about" element={<About />}></Route>
              <Route exact path="/contact" element={<Contact />}></Route>
            </Routes>
            {
              <CounterPages>
                id={this.state.pages[this.state.index - 1].id}
                onAddPage={this.handleAddPage}
                onDeletePage={this.handleDeletePage}
                onNextPage={this.handleNextPage}
                onBackPage={this.handleBackPage}
              </CounterPages>
            }
          </div>
        </BrowserRouter>
        {/* this is for loading every page at once */}
        {/* <BrowserRouter>
      {this.state.pages.map(page => <CounterPages>
        id={page.id}
        onAddPage={this.handleAddPage}
        onDeletePage={this.handleDeletePage}
        </CounterPages>)}
        </BrowserRouter> */}
      </div>
    );
  }

  getRoute() {
    let tempVar = "/" + this.state.route;
    return tempVar;
  }
}

export default App;
